use std::fmt;

// The returned opaque type is parameterised by T — each T gives a different opaque type
fn wrap<T: fmt::Display + Clone>(val: T) -> impl fmt::Display + Clone {
    val
}

// A function that adapts T into a more complex impl:
fn with_label<T: fmt::Display>(label: &'static str, val: T) -> impl fmt::Display {
    // Returns a closure-based adapter (since Display is available)
    struct Labeled<T> { label: &'static str, val: T }
    impl<T: fmt::Display> fmt::Display for Labeled<T> {
        fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
            write!(f, "[{}] {}", self.label, self.val)
        }
    }
    Labeled { label, val }
}

// Return type carries the generic:
fn zip_with_index<T: Clone>(items: Vec<T>) -> impl Iterator<Item = (usize, T)> {
    items.into_iter().enumerate()
}

