fn flip<A, B, C, F: Fn(A, B) -> C>(f: F) -> impl Fn(B, A) -> C {
    move |b, a| f(a, b)
}

fn memoize_once<T: Clone, F: Fn() -> T>(f: F) -> impl FnMut() -> T {
    let mut cache: Option<T> = None;
    move || {
        if let Some(ref v) = cache {
            v.clone()
        } else {
            let v = f();
            cache = Some(v.clone());
            v
        }
    }
}

